//vip.opstream12.com/share/923cac285a4b2e03d3d618857c250eee","link_m3u8":"https://vip.opstream12.com/20220610/18496_07db1674/index.m3u8"},{"name":"14","slug":"14","filename":"Black-Butler-S3-tap-14","link_embed":"https://vip.opstream12.com/share/0f861d5d09a20da1a9e7fbab8a0a6877","link_m3u8":"https://vip.opstream12.com/20220610/18497_bc460d56/index.m3u8"},{"name":"15","slug":"15","filename":"Black-Butler-S3-tap-15","link_embed":"https://vip.opstream12.com/share/fd1be5bb737d23e0236b52c9cb69d514","link_m3u8":"https://vip.opstream12.com/20220610/18498_73987e02/index.m3u8"}]}],"time":"25 phút/tập","description":"<p>Đầy kinh ngạc và phấn khích, đoàn ca kịch Noah Arc Circus đã thu phục khán giả bằng những màn trình diễn mãn nhãn của họ. Tuy nhiên, những hành động tuyệt vời này không đến mà không có giá. Trẻ em đã mất tích một cách bí ẩn xung quanh London, tương quan với phong trào của các nhóm. Không lo lắng trước những vụ bắt cóc này, Nữ hoàng Victoria đã gửi con chó bảo vệ khét tiếng của mình, Ciel Phantomhive, và người quản gia quỷ trung thành của ông, Sebastian Michaelis, thực hiện một nhiệm vụ bí mật để tìm những đứa trẻ mất tích này. Tuy nhiên, cố gắng cân bằng các tiết mục xiếc mới của họ với cuộc điều tra bí mật của họ dưới đỉnh lớn, được chứng minh là một thách thức khá lớn. Với việc những người biểu diễn khác ngày càng nghi ngờ và mối đe dọa từ ân nhân bí ẩn của rạp xiếc đang rình rập trên đầu, những gì hai người khám phá ra sẽ khiến Ciel bị lung lay về cốt lõi của mình.</p>","tmdb":{"type":null,"id":"","season":null,"vote_average":0,"vote_count":0},"modified":"2022-06-11T17:09:25.000Z","_image_preserved":true},{"id":"62a4ccb87a956fb5db09c89e","_id":"62a4ccb87a956fb5db09c89e","title":"Digimon 1999","origin_name":"Digimon Adventure (1999)","slug":"digimon-adventure-1999","year":1999,"type":"hoathinh","genre":[{"id":"620a21b2e0fc277084dfd0c5","name":"Hành Động","slug":"hanh-dong"},{"id":"620a2282e0fc277084dfd435","name":"Viễn Tưởng","slug":"vien-tuong"},{"id":"620a